import UIKit
import CryptoKit

class BankingApp {
    var accountBalance: Double = 0.0
    private let encryptionKey = SymmetricKey(size: .bits256)

    func processTransaction(amount: Double, isDeposit: Bool) -> Bool {
        if isDeposit {
            accountBalance += amount
        } else {
            if amount <= accountBalance {
                accountBalance -= amount
            } else {
                return false // Insufficient funds
            }
        }
        return true
    }

    func getAccountBalance() -> String {
        return "Account Balance: $\(String(format: "%.2f", accountBalance))"
    }

    func encryptData(data: String) -> String? {
        let dataToEncrypt = Data(data.utf8)
        let sealedBox = try? AES.GCM.seal(dataToEncrypt, using: encryptionKey)
        return sealedBox?.combined?.base64EncodedString()
    }

    func decryptData(encryptedData: String) -> String? {
        guard let data = Data(base64Encoded: encryptedData),
              let sealedBox = try? AES.GCM.SealedBox(combined: data) else {
            return nil
        }
        let decryptedData = try? AES.GCM.open(sealedBox, using: encryptionKey)
        return decryptedData != nil ? String(data: decryptedData!, encoding: .utf8) : nil
    }
}

